#include <bits/stdc++.h>
using namespace std;

class Validate : public exception {
public:
    const char* what() const noexcept override {
        return "Person is not eligible to vote";
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T, age;
    if (!(cin >> T)) return 0;
    while (T--) {
        cin >> age;
        try {
            if (age < 18) throw Validate();
            cout << "Eligible to vote" << '\n';
        } catch (const Validate& e) {
            cout << e.what() << '\n';
        }
    }
    return 0;
}

code.Java:
import java.io.*;

class Validate extends Exception {
    public Validate() {
        super("Person is not eligible to vote");
    }
}

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            int age = Integer.parseInt(br.readLine().trim());
            try {
                if (age < 18) throw new Validate();
                sb.append("Eligible to vote");
            } catch (Validate e) {
                sb.append(e.getMessage());
            }
            if (i != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

