class Validate(Exception):
    def __init__(self, message="Person is not eligible to vote"):
        super().__init__(message)

def check_age(age):
    if age < 18:
        raise Validate()
    return "Eligible to vote"

def main():
    import sys
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    out = []
    idx = 1
    for _ in range(T):
        age = int(data[idx])
        idx += 1
        try:
            out.append(check_age(age))
        except Validate as e:
            out.append(str(e))
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

